var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_QM","text":{"KOREA":"어머니가 그랬어.","JPN":"お母さんが言ってた。","ENG":"Mother used to tell me.","TWN":"媽媽是這麼說的。"},"stage":{"bg":"SKY_NIGHT","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_QM","text":{"KOREA":"저 하늘에 반짝이는 별님들은 전부 세상 누군가의 소망이 만든 빛이라고.","JPN":"空に輝くお星さまは皆、この世界の誰かの願いが生み出した光なんだって。","ENG":"All the stars that twinkle in the sky are lights made from the wishes of people everywhere.","TWN":"那天上閃爍的星星，全都是世上某人的願望所化成的光芒。"},"stage":{"bg":"SKY_NIGHT","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_QM","text":{"KOREA":"그리고 소망이 아주 아주 커지면, 별님은 어느 때보다 밝게 빛나면서 이 땅에 떨어진대.","JPN":"そしてその願いが大きくなると、お星さまはこれまでにないほどに眩く光って、大地に落ちるの。","ENG":"And when a wish gets really big, the star shines brightly as ever and falls to the ground.","TWN":"而當願望變得非常非常大的時候，星星會比任何時候都更加明亮地閃耀，然後落到這片土地上。"},"stage":{"bg":"SKY_NIGHT","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_QM","text":{"KOREA":"그 소망을 가진 사람의 꿈을 이뤄주기 위해서 말이야.","JPN":"願い事をした人の夢を叶えてあげるために。","ENG":"She said it fell to make that person's wish come true.","TWN":"為了實現那個懷抱希望之人的夢想。"},"stage":{"bg":"SKY_NIGHT","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_QM","text":{"KOREA":"응? 나도 소망이 있냐고?","JPN":"え？　私の願い？","ENG":"Hmm? Do I have a wish?","TWN":"嗯？你問我也有願望嗎？"},"stage":{"bg":"SKY_NIGHT","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_QM","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SKY_NIGHT","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_QM","text":{"KOREA":"있긴 하지만… 그게 뭔지는 비밀이야.","JPN":"あるけど……内緒だよ。","ENG":"I do, but... that's a secret.","TWN":"有是有，但是保密。"},"stage":{"bg":"SKY_NIGHT","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_QM","text":{"KOREA":"이것도 비밀인데, 난 너희가 만드는 토마토를 제일 좋아하거든.","JPN":"それからこれも内緒だけど、私はあなたたちが作るトマトが一番好きなの。","ENG":"This is also a secret, but I like the tomatoes you make the most.","TWN":"再和你說個秘密喔，其實我最喜歡你們產的蕃茄。"},"stage":{"bg":"SKY_NIGHT","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_QM","text":{"KOREA":"내일은 특별한 날이니까. 제일 잘 익은 토마토 한 소쿠리만 따갈게.","JPN":"明日は特別な日だから、一番熟したトマトを少しもらうね。","ENG":"Tomorrow's a special day, so I'll be taking just one basket full of the ripest tomatoes.","TWN":"明天是特別的日子。我要摘一籃子最熟的蕃茄。"},"stage":{"bg":"SKY_NIGHT","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_QM","text":{"KOREA":"…내일이 무슨 날이냐고?","JPN":"……明日が何の日なのかって？","ENG":"...What day is it tomorrow?","TWN":"……你們問明天是什麼日子？"},"stage":{"bg":"SKY_NIGHT","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_QM","text":{"KOREA":"후후, 막내 새싹들은 모르겠구나.","JPN":"ふふ、新芽たちはまだ知らないんだね。","ENG":"Haha, I guess the youngest sprouts wouldn't know.","TWN":"呵呵，小傢伙們還不知道呢。"},"stage":{"bg":"SKY_NIGHT","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_QM","face":"UNIT_LAUGH"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_QM","text":{"KOREA":"내일은 말이야, 바로 내…","JPN":"明日はね、私の……","ENG":"Tomorrow is my–","TWN":"明天，就是我的……"},"stage":{"bg":"SKY_NIGHT","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_QM","text":{"KOREA":"어…? 방금 별님이 떨어졌어.","JPN":"え……？　今お星さまが落ちたよ。","ENG":"Oh...? A star just fell.","TWN":"咦……？剛才有顆星星掉下來了。"},"stage":{"bg":"SKY_NIGHT","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_QM","text":{"KOREA":"실제로는 처음 봐.","JPN":"実際に見るのは初めて。","ENG":"This is my first time seeing one.","TWN":"這是我第一次見到呢。"},"stage":{"bg":"SKY_NIGHT","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_QM","face":"UNIT_LAUGH"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_QM","text":{"KOREA":"누구 소망을 이뤄주러 온 거겠지?","JPN":"誰かの願いを叶えてあげるのかな？","ENG":"It must've come down to grant someone's wish, right?","TWN":"是來實現誰的願望的吧？"},"stage":{"bg":"SKY_NIGHT","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_QM","text":{"KOREA":"혹시 별님이 내가 만든 꽃차도 좋아하려나?","JPN":"お星さま、私が作った花茶も好きかな？","ENG":"Do you think the star will like the flower tea I made?","TWN":"它會喜歡我做的花茶嗎？"},"stage":{"bg":"SKY_NIGHT","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_QM","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SKY_NIGHT","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_QM","text":{"KOREA":"나 금방 다녀올게!","JPN":"行ってくるね！","ENG":"I'll be right back!","TWN":"我馬上回來！"},"stage":{"bg":"SKY_NIGHT","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_QM","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"아야야…","JPN":"いたた……","ENG":"Oww...","TWN":"哎呀……哎呀……"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_DESPAIR"},"C":{"char_id":"SOLOVEY_ADMIN_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"나뭇가지에 걸려 망정이지. 그대로 떨어졌으면 목이 돌아갈 뻔했네.","JPN":"木の枝に引っかかって助かった……そのまま落ちたら首が捻じれるとこだったよ。","ENG":"Thank goodness I got caught on a tree branch. If I had fallen down the whole way, my neck would have been twisted.","TWN":"幸好被樹枝掛住了。如果直接摔下去，脖子一定會斷掉。"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SOLOVEY_ADMIN_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"가만… 나무라고?","JPN":"ちょっと待ってよ。木……？","ENG":"Wait a second... a tree?","TWN":"等等……樹？"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"SOLOVEY_ADMIN_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"격리 공간 속에 왜 식물이 자라고 있는 거지?","JPN":"隔離空間にどうして植物があるの？","ENG":"Why is there a tree growing in a isolated space?","TWN":"隔離空間裡為什麼會長著植物？"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SOLOVEY_ADMIN_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_QM","text":{"KOREA":"앗, 별님? 왜 거기에 매달려 계신가요?","JPN":"あっ、お星さま？　どうしてそこにぶら下がっているんですか？","ENG":"Oh, Miss Star? Why are you dangling up there?","TWN":"啊，星星啊？你為什麼掛在那裡？"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLOVEY_ADMIN_NULL_QM","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"엥? 넌 누구냐?","JPN":"え？　あなたは誰？","ENG":"Huh? Who are you?","TWN":"咦？你是誰？"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SOLOVEY_ADMIN_NULL_QM","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"우와와- 별님이 내 이름을 물어봤어…!","JPN":"わああ～！　お星さまに名前を聞かれた……！","ENG":"Wow! The star asked my name...!","TWN":"哇啊啊——星星問了我的名字……！"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"}}}}]`);export{e as default};